
export function getNavList() {
  return Promise.resolve([
    {
      name: 'equiment',
      path: '/equiment',
      meta: {title: '设备管理',icon: 'table'},
      children: [
        {
          name: 'equimentInfo',
          path: '/equiment/info',
          meta: {title: '设备信息',icon: 'table'}
        }
      ]
    }
  ])
}


